var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"올바른 보도, 진실된 정보. 그로니아 국영 뉴스. 방금 들어온 속보입니다.","JPN":"正しい報道、真なる情報。グロニア国営ニュース。ただいま入ってきた速報です。","ENG":"Reporting in with the truth, Gronia National News. Breaking news.","TWN":"真實的報導，正確的資訊，格羅尼亞國境新聞。 現在為您插播一則快訊。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"보안국은 청사를 습격한 신원 불명의 용병에 대해 공개 수배령을 내렸습니다.","JPN":"保安局は庁舎を襲撃した身元不明の傭兵について、公開手配しました。","ENG":"The Department of National Security has issued a bounty for the unidentified mercenary attacking its main office.","TWN":"安全局已經針對襲擊安全局大樓的傭兵發布通緝令。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"비슷한 인상착의의 인물을 목격하신 분께서는 보안국 및 경찰, 수도 방위 부대에 연락 바랍니다.","JPN":"似たような人相の人物を目撃した方は、保安局及び警察、首都防衛部隊までご連絡ください。","ENG":"Anyone who has any information or has seen someone with a similar description as the mercenary should contact the Department of National Security, police, or Capital Defense Unit.","TWN":"民眾若有發現類似穿著的人物，請盡速通報安全局、警察局，或是首都防衛隊。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"한편, 정부는 긴급 기자 회견을 통해 건국절 기념식을 강행하겠다는 의사를 표명했습니다.","JPN":"一方、政府は緊急記者会見で建国記念式を強行するという意を表明しました。","ENG":"Meanwhile, the government expressed its intention to go ahead with the National Foundation Day ceremony via an emergency press conference.","TWN":"另一方面，政府緊急召開記者會，表示國慶典禮將如期舉行。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"건국 선언식이 있었던 자정부터 시작되는 행사는, 동이 틀 무렵 열릴 공연회를 끝으로 그 대미를 장식하게 됩니다.","JPN":"建国宣言式が行われた午前0時から始まる行事は、明け方、最後を飾る公演会の後、幕を下ろす予定です。","ENG":"The event, starting at midnight, which was when the founding ceremony was originally held, will end with a concert at dawn.","TWN":"整個國慶活動從發表建國宣言的子夜開始，最後以黎明時分的演奏會作為完美的結束。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"타나베린의 시민들은 이른 시각부터 퍼레이드가 열릴 중앙로에 앞다퉈 모여 국기를 흔들고 있습니다.","JPN":"タナベリンの市民は早朝からパレードが始まる中央通りへ集まり、国旗を振っています。","ENG":"Citizens of Tanaberin have been gathering since early in the morning to wave flags on the central road where the parade will be held.","TWN":"而預備要舉行遊行的中央路上，一早就聚集大群達那貝林的市民揮舞著國旗。"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"시민들이 제창하는 국가를 들어 보십시오. 이것이야말로 우리나라의 기상, 우리나라의 미래…….","JPN":"市民の歌う国歌をお聞きください。これこそ我が国の気性、我が国の未来……","ENG":"Listen to the sound of these citizens singing the national anthem. This is the spirit of our country, the future of our country...","TWN":"請看看市民們揮舞著國旗的盛況，這才是我們國家最美的景色，國家的未來……"},"stage":{"bg":"HARMONY_01_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아. 간만에 인사하네요, 상상 친구 씨.","JPN":"あ。久しぶりだね、エア友さん。","ENG":"Ah. It’s been a while, hasn’t it, Mr. Imaginary Friend?","TWN":"哇，好久不見啦，我想像中的朋友。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"터무니없는 사람들이랑 엮이는 바람에 정신적으로 힘들었거든요.","JPN":"とんでもない人たちに巻き込まれて、精神的にしんどかったんだよね。","ENG":"I’ve really been under a lot of mental stress these days because I’ve been caught up with some ridiculous people.","TWN":"被那些莫名其妙的人搞得真的心好累喔。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이야. 모난 구석 안 보이려고 그렇게 애썼는데, 이번 한 방으로 텄네요. 텄어.","JPN":"いやぁ。あんなに角が立たないように頑張ったのに、今度の一発でパーだよ。パー。","ENG":"I tried so hard not to stick out, but all that effort was for nothing.","TWN":"虧我已經盡量抱持低調，結果現在都露餡兒啦！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭘 그렇게 중얼거려? 누구랑 통화하니?","JPN":"何をそんなにブツブツ言ってるの？　誰かと電話中？","ENG":"What are you mumbling about? Are you making a call or something?","TWN":"你在自言自語什麼？還是你在跟誰講電話？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"흐익?!","JPN":"ひいっ！？","ENG":"Hwagh?!","TWN":"嚇？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"왜 그래? 갑자기 말을 걸어서 놀랐으려나?","JPN":"どうしたの？　いきなり話しかけられてびっくりしちゃった？","ENG":"Huh? What's wrong? Did I surprise you?","TWN":"幹嘛？我突然跟你說話嚇到你嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 네……. 그야 기척도 없이 다가오셨으니까요.","JPN":"あ、はい……そりゃあ気配もなく近づいてこられたので。","ENG":"Oh, yeah... You snuck up on me.","TWN":"喔，對啊……誰叫你一聲不響地冒出來。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……그보다, 전 사람이랑 부대끼는 취미는 없어서요.","JPN":"……それより私、あまり人と馴れ馴れしくする趣味はないんです。","ENG":"...More than that, I don’t like being around people.","TWN":"……然後，我不喜歡和人太靠近，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"다음부터는 가급적 안전 거리를 지켜 주시면 좋겠는데요.","JPN":"次からはなるべく安全距離を取っていただきたいんですけど。","ENG":"Please keep a safe distance as much as possible from now on.","TWN":"下次可以麻煩你保持社交安全距離嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 원한다면야.","JPN":"そう。お望みどおりに。","ENG":"Sure thing, whatever you want.","TWN":"好喔，你說了算。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"수송기에 태워 주신 건 고마워요. 그러니까…….","JPN":"輸送機に乗せてくださったのはありがとうございました。えっと……","ENG":"Thanks for giving us a lift on the transport. Uhh...","TWN":"謝謝你讓我們搭你的運輸機，那個……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"알렉스 씨.","JPN":"アレックスさん。","ENG":"It’s Alex.","TWN":"雅蕾克絲小姐。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네. 알렉스 씨가 아니었으면 거동도 불편한 노인 분이랑 같이 도주극을 찍었을 테니까요.","JPN":"はい。アレックスさんじゃなかったら、動きにくい老人の方と一緒に逃走劇を撮っていたはずですから。","ENG":"Right, well. If it weren’t for you, It’d be like operation Saving Disabled Old Lady, and that wouldn’t have gone well.","TWN":"對，若不是雅蕾克絲小姐，我和行動不便的老人可能會上演落難記。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으응……. 사람은 집이 최고지……. 아암…….","JPN":"ううん……人には家が最高よ……そう……","ENG":"Yes... Home sweet home, they say. Yes, yes...","TWN":"嗯嗯……還是家裡舒服……唉唉……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"여기가 집보다 나아요, 아주머니.","JPN":"ここが家よりマシですよ、おばさん。","ENG":"It’s better to be here than home, Madam.","TWN":"這裡比你家還好喔，伯母。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"관리국 소속이라고 했으니까 선내는 치외법권이거든요. 그로니아에서 제일 안전한 곳이죠.","JPN":"管理局の所属って言ってましたから、船内は治外法権なんですよ。グロニアで一番安全なところです。","ENG":"This ship belongs to the Administration so it’s out of their jurisdiction. It’s the safest place in Gronia.","TWN":"由於隸屬於管理局，因此艙內是屬於治外法權，可以說是格羅尼亞最安全的地方呢！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"간식 뺏긴 레서판다 같은 표정으로 다니면서 똘똘하구나.","JPN":"おやつを取られたレッサーパンダのような顔なのに、お利口さんね。","ENG":"You’re clever though you always walk around like a red panda who has just lost her snack.","TWN":"雖然你一臉好像零食被搶走的小貓熊，沒想到滿聰明嘛～"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……같은 사회인끼리 말씀은 좀 가려서 해 주시죠?","JPN":"……社会人同士、言葉を選んでもらえますか？","ENG":"…Maybe have some respect when talking to your colleague, would you?","TWN":"……大家都是社會人士，說話可以放尊重一點嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후훗. 좋아. 그렇지만 귀엽다는 건 쓸모 있는 장점이야, 중사님.","JPN":"ふふっ。いいよ。でもかわいいってことは使える長所なのよ、軍曹。","ENG":"Fuu fuu. All right. But being so cute is a useful strength, Sergeant.","TWN":"呵呵～可是中士，可愛是一個很大的優勢欸。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그래요. 귀여운 손님이지요. 우리 딸애 어릴 때를 꼭 닮았어요.","JPN":"そうです。かわいらしいお客さんでしょう。幼い頃の娘とそっくりです。","ENG":"Right. She’s such an adorable guest. My daughter was just like her when she was young.","TWN":"是啊，這位客人真的很可愛呢，和我女兒小時候好像。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"얼굴만 닮았으면 좋겠네요. 나이 먹고 저런 굴곡 많은 삶을 살기는 싫어서요.","JPN":"顔だけ似たいですね。年取ってそんな波乱万丈な人生を生きたくはないんです。","ENG":"I hope only our faces are similar. I don’t want to live a life full of so many ups and downs when I get older.","TWN":"希望只有臉長得像就好，我可不想長到像她那把年紀卻過得那麼辛苦。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런데 무슨 일이세요? 혹시 이제 와서 보안국에 넘기려는 건 아니죠?","JPN":"ところでどうしました？　もしかして、今更保安局に私たちを渡すつもりじゃないですよね？","ENG":"Anyways, what’s going on? You aren’t going to hand us over to the National Security, are you?","TWN":"不過請問你突然冒出來是有什麼事嗎？應該不是想把我們交給安全局吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"안심해. 잠시 아주머니와 할 얘기가 있을 뿐이니까.","JPN":"安心しなさい。ちょっとおばさんと話したいだけだから。","ENG":"No need to worry. I just need to speak with the madam for a little while.","TWN":"放心～我只是想跟伯母聊幾句而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"잠시 시간 내 줄 수 있지?","JPN":"時間をもえらるかしら？","ENG":"Could you spare me a minute?","TWN":"方便聊一下嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트 씨가 같이 듣는다면요. 전 간병인이 아니라 일개 군인이라서요.","JPN":"レヴナントさんが一緒に聞くのなら。私は看病人じゃなくてただの軍人なんで。","ENG":"If Revenant can listen, too. I’m just a soldier, not a caretaker.","TWN":"請亡靈小姐一起吧？畢竟我又不是看護，只是區區一介軍人。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 아마 의무실에 있을 거야. 이리로 불러와 줄래?","JPN":"わかった。多分医務室にいるはずよ。こっちへ呼んできてくれる？","ENG":"Sure. She’s probably in the infirmary. Could you call her over here?","TWN":"好啊，她應該在醫務室，可以幫我找她過來嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그럴 필요 없어. 이미 와 있으니까.","JPN":"その必要はないよ。すでに来ているから。","ENG":"No need. I’m already here.","TWN":"不用了，我在這裡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트 씨, 움직여도 돼요?","JPN":"レヴナントさん、動いていいんですか？","ENG":"Revenant, is it really okay for you to be moving around?","TWN":"亡靈小姐，你可以這樣走動嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"후훗. 그럼. 중사 덕분이야.","JPN":"ふふっ。もちろん。軍曹のおかげだよ。","ENG":"Fuu fuu. Of course. I’m fine. Thanks to you.","TWN":"呵呵，沒問題，這都要謝謝你。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그렇지만, 안젤라 씨는 연락이 끊겨서…….","JPN":"でも、アンジェラさんからは連絡が途絶えて……","ENG":"Yeah, but we lost contact with Angela...","TWN":"不過，還沒聯絡上安潔拉小姐……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……처음 만날 때도 홀연히 나타난 애야. 괜찮아.","JPN":"……出会った時にも突然現れた子だよ。大丈夫。","ENG":"When we first met she just appeared out of nowhere back then too. It’ll be okay.","TWN":"……她本來就是這樣神出鬼沒，沒事的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"먼저 좋은 소식이야. 정부 측이 우리에게 이륙 허가를 내 줬어.","JPN":"まずはいい知らせから。政府が私たちの離陸を許可したの。","ENG":"Let’s start with the good news. The government has given us permission for takeoff.","TWN":"先跟大家說個好消息，政府已經批准我們的起飛申請。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래……?","JPN":"そう……？","ENG":"Is that so?","TWN":"是嗎……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"왜, 뭔가 문제가 있으려나?","JPN":"何？　なんか問題でもあるの？","ENG":"Huh, is there something wrong?","TWN":"怎麼了？有什麼問題嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"나와라, 레버넌트.","JPN":"出てこい、レヴナント。","ENG":"Revenant, come out.","TWN":"出來吧，亡靈。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"왜요? 벌써 형장에 갈 시간이 됐나요?","JPN":"どうしたんですか？　もう刑場に行く時間ですか？","ENG":"Why? Is it time for the execution already?","TWN":"為什麼？這麼快就要去刑場啦？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"아니. 단두대가 너를 만나러 이리로 오고 있어.","JPN":"いや。断頭台が君に会うためにこっちへ向かっている。","ENG":"No. The guillotine is on its way to meet you.","TWN":"不是，是斷頭台找你找到這裡來了。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"단두대라면……. 모르스가 여기 왔군요.","JPN":"断頭台……モールスがここに来たんですね。","ENG":"Guillotine... Mors is here.","TWN":"斷頭台……你是說莫爾斯嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……그래. 부끄럽지만 지금 우리에겐 그 자를 감당할 힘이 없다.","JPN":"……そうだ。恥ずかしながら、今の私たちにはその者の相手をする力がない。","ENG":"...Indeed. It’s embarrassing to admit, but we don’t have the necessary firepower to handle her right now.\\n\\n","TWN":"……對，說來慚愧，但我們現在沒有能力可以應付她。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"우리가 무능하다고 포장하면 협상이라도 해 볼 기회는 생기겠지.","JPN":"私たちが無能であるように仕立てれば、話し合うチャンスは作れるだろう。","ENG":"Maybe if we come across as incompetent, we’ll have a chance to negotiate.","TWN":"我們直接示弱的話，或許還有談判的空間。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하지만, 그러면 국장님은…….","JPN":"しかし、それでは局長は……","ENG":"But if that’s the case, Chief, you...","TWN":"可是這樣的話，部長你……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"내가 지금까지 이 자리에 앉아 있는 건 지난번 건의 뒷수습 때문이야.","JPN":"私がまだここにいるのは、この前の件の後始末をするためだ。","ENG":"The reason I’ve been sitting here up to this point is to clean up the mess from the last operation.","TWN":"我之所以可以坐上現在這個位置，是因為上次事件的善後。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"자네의 마지막 임무야, 레버넌트.","JPN":"君の最後の任務だ、レヴナント。","ENG":"This is the final mission for you, Revenant.","TWN":"這是你最後的任務，亡靈。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"평화를 위해, 차라리 아무도 모르게 사라져다오.","JPN":"平和のために、いっそ誰も知らぬうちに消えてくれ。","ENG":"For the sake of peace, I want you to disappear quietly.","TWN":"為了國家的和平，請你默默消失吧。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"관리국 정보부 사람에게 이민을 제안 받은 적은 몇 번 있었어.","JPN":"管理局の情報部の人から移民を提案されたことは何回かあったよ。","ENG":"I was given the option to emigrate several times from an intelligence agent of the Administration.","TWN":"管理局情報部的人有跟我提過幾次移民的事，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하지만 이렇게까지 무리를 할 만큼 내가 가치 있는 사람이었던가?","JPN":"でもここまで無理をするほど、私って価値のある人だっけ？","ENG":"But isn’t doing it this way a little too much? Am I really that important?","TWN":"可是我有讓他們做到這種地步的價值嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아. 오해하지 마. 이번 일은 정보부와 관계없어.","JPN":"あ。誤解しないで。今度のことは情報部とはなんの関係もないの。","ENG":"Ah. Don’t misunderstand. This isn’t related to that intelligence agent at all.","TWN":"喔，別誤會，這次的事和情報部無關。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래? 그런데 왜 보안국과 척을 졌지?","JPN":"そう？　でもどうして保安局といがみ合ってるの？","ENG":"Then why are you opposing the will of the National Security?","TWN":"是嗎？那為什麼會和安全局結仇？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"간단해. 아주 오래된 그림자 때문이야.","JPN":"簡単よ。とても古いシャドウのせいなの。","ENG":"It’s simple. It’s because of an ancient Shadow.","TWN":"原因很簡單，因為古老的暗影。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……그림자?","JPN":"……シャドウ？","ENG":"...A Shadow?","TWN":"……暗影？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};